[The Server Monitoring spec|https://github.com/mongodb/specifications/blob/master/source/server-discovery-and-monitoring/server-monitoring.rst#heartbeatfrequencyms] explicitly forbids setting a heartbeatFrequencyMS of less than 500ms:

{quote}
For both multi- and single-threaded drivers, the driver MUST NOT permit users to configure it less than minHeartbeatFrequencyMS (500ms).
{quote}

Setting a heartbeatFrequencyMS of less than 500ms may only have an observable difference when monitoring 4.4+ servers with streamable ismaster. Previous polling behavior appears to respect the 500ms minimum delay looking at [x/mongo/driver/topology/server.go|https://github.com/mongodb/mongo-go-driver/blob/5ce8618cbdc4daecb6615b11dde027e8384139ad/x/mongo/driver/topology/server.go#L481:L481]).

h3. Detailed steps to reproduce the problem?

The program below will demonstrate the leak by incrementally outputting goroutine counts. It also exposes a pprof server at localhost:8080 for profile analysis.
{code:go}
package main

import (
	"context"
	"fmt"
	"log"
	"net/http"
	_ "net/http/pprof"
	"runtime"
	"time"

	"go.mongodb.org/mongo-driver/bson"
	"go.mongodb.org/mongo-driver/mongo"
	"go.mongodb.org/mongo-driver/mongo/options"
)

func main() {
	go func() {
		log.Println(http.ListenAndServe("localhost:8080", nil))
	}()

	ctx := context.Background()
	uri := "mongodb://localhost:27017"
	opts := options.Client().ApplyURI(uri).SetCompressors([]string{"zstd"})

	client, err := mongo.Connect(ctx, opts)
	if err != nil {
		log.Fatalf("Error connecting to mongo server: %v", err)
	}
	defer func() {
		if err = client.Disconnect(ctx); err != nil {
			panic(err)
		}
	}()

	connectCtx, cancel := context.WithTimeout(ctx, time.Second*5)
	defer cancel()
	if err := client.Ping(connectCtx, nil); err != nil {
		log.Fatalf("Error pinging mongo server: %v\n", err)
	}

	type TestStruct struct {
		X string `bson:"x"`
	}
	collection := client.Database("leaktest").Collection("testcollection")
	if _, err := collection.InsertOne(ctx, TestStruct{X: "123"}); err != nil {
		log.Fatalf("Error intializing collection: %v\n", err)
	}

	for i := 0; i < 30; i++ {
		var doc TestStruct
		if err := collection.FindOne(ctx, bson.M{"x": "123"}).Decode(&doc); err != nil {
			log.Fatalf("Error fetching document: %v\n", err)
		}
		time.Sleep(1 * time.Second)
		runtime.GC()
		fmt.Printf("Goroutines: %d\n", runtime.NumGoroutine())
	}
}

{code}
